// Define optimization problem
int minimizeCost(int max_cost, std::vector<Item> budget_items) { 
   // Initialize min_cost 
   int min_cost = 0; 

   // Choose items that add up to max_cost or less
   for (Item item : budget_items) {
      if ((min_cost + item.cost) <= max_cost) {
         min_cost += item.cost;
      } 
   } 

   return min_cost; 
} 

