function camelCaseToSnakeCase(str){ 
  let result = str[0].toLowerCase(); 
  for (let i = 1; i < str.length; i++) { 
    if (str.charAt(i) === str.charAt(i).toUpperCase()) 
      result += "_" + str.charAt(i).toLowerCase(); 
    else
      result += str.charAt(i); 
  } 
  return result; 
}

