                { 
                    C[i][j] += A[i][k] * B[k][j]; 
                } 
            } 
        } 
        return C; 
    } 

    static void printMatrix 
                           (int[][] matrix) 
    { 
        for (int i = 0; i < N; i++) 
        { 
            for (int j = 0; j < N; j++) 
            { 
                System.out.print(matrix[i][j] + " "); 
            } 
            System.out.println(); 
        } 
    } 

    public static void main (String[] args) 
    { 
        int[][] A = { { 1, 1, 1 },  
                      { 2, 2, 2 },  
                      { 3, 3, 3 },  
                      { 4, 4, 4 },  
                      { 5, 5, 5 } }; 

        int[][] B = { { 1, 1, 1 },  
                      { 2, 2, 2 },  
                      { 3, 3, 3 },  
                      { 4, 4, 4 },  
                      { 5, 5, 5 } }; 

        int[][] C = multiply(A, B); 
        printMatrix(C); 
    } 
}

